CREATE DATABASE IF NOT EXISTS warehouse_manager
    CHARACTER SET utf8mb4
    COLLATE utf8mb4_unicode_ci;

USE warehouse_manager;

-- ------------------------------------------------------------
-- Bảng DanhMuc
-- ------------------------------------------------------------
CREATE TABLE IF NOT EXISTS DanhMuc (
    MaDM    VARCHAR(10)   NOT NULL,
    TenDM   VARCHAR(100)  NOT NULL,
    CONSTRAINT PK_DanhMuc PRIMARY KEY (MaDM)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ------------------------------------------------------------
-- Bảng SanPham
-- ------------------------------------------------------------
CREATE TABLE IF NOT EXISTS SanPham (
    MaSP    INT            NOT NULL AUTO_INCREMENT,
    TenSP   VARCHAR(200)   NOT NULL,
    MoTa    TEXT,
    Gia     DECIMAL(15, 0) NOT NULL DEFAULT 0,
    SoLuong INT            NOT NULL DEFAULT 0,
    DanhMuc VARCHAR(10)    NOT NULL,
    CONSTRAINT PK_SanPham    PRIMARY KEY (MaSP),
    CONSTRAINT FK_SP_DanhMuc FOREIGN KEY (DanhMuc) REFERENCES DanhMuc(MaDM)
        ON UPDATE CASCADE
        ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

